package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidInputStreamAndCharsetAndFormat() throws IOException {
        // Arrange
        String csvContent = "header1,header2\nvalue1,value2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        CSVFormat format = mock(CSVFormat.class);
        InputStreamReaderStub readerStub = new InputStreamReaderStub(inputStream, StandardCharsets.UTF_8);

        try (MockedStatic<CSVParser> mockedStatic = Mockito.mockStatic(CSVParser.class, Mockito.CALLS_REAL_METHODS)) {
            // Mock parse(Reader, CSVFormat) to return a dummy CSVParser instance
            CSVParser dummyParser = mock(CSVParser.class);
            mockedStatic.when(() -> CSVParser.parse(any(java.io.Reader.class), eq(format))).thenReturn(dummyParser);

            // Act
            CSVParser result = CSVParser.parse(inputStream, StandardCharsets.UTF_8, format);

            // Assert
            assertNotNull(result);
            assertSame(dummyParser, result);

            // Verify that the static parse(Reader, CSVFormat) method was called with an InputStreamReader wrapping the inputStream
            mockedStatic.verify(() -> CSVParser.parse(any(java.io.Reader.class), eq(format)));
        }
    }

    // Helper stub class to simulate InputStreamReader constructor for verification if needed
    static class InputStreamReaderStub extends java.io.InputStreamReader {
        public InputStreamReaderStub(InputStream in, java.nio.charset.Charset cs) {
            super(in, cs);
        }
    }
}
